import{c as s,Q as a,j as p,m as t}from"./chunks/framework.Bhbi9jCp.js";const q=JSON.parse('{"title":"分层架构总图与一个方块的生命周期","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/12-分层架构总图与一个方块的生命周期.md","filePath":"minecraftLearning/12-分层架构总图与一个方块的生命周期.md","lastUpdated":1781674740000}'),e={name:"minecraftLearning/12-分层架构总图与一个方块的生命周期.md"};function l(i,n,o,c,r,u){return a(),p("div",null,[...n[0]||(n[0]=[t(`<h1 id="分层架构总图与一个方块的生命周期" tabindex="-1">分层架构总图与一个方块的生命周期 <a class="header-anchor" href="#分层架构总图与一个方块的生命周期" aria-label="Permalink to &quot;分层架构总图与一个方块的生命周期&quot;">​</a></h1><p>前面十一篇,我们从体素世界一路拆到注册表:地形怎么算出来、区块怎么画、20 TPS 怎么驱动世界、数据怎么存盘、方块和实体和流体到底是什么、最后一切类型怎么登记在注册表里。知识点很多,但如果只是记住一堆零散名词,过几天就忘了。</p><p>这一篇不引入任何新机制,只做一件事:<strong>把这些点缝成一张图,再让一个方块在这张图上&quot;活一遍&quot;</strong>。当你能闭着眼睛画出这张分层图、能讲清一格石头从生成到存盘再到加载走了哪些层,你就真正理解了 Minecraft 的骨架,而不只是背下了它的零件。</p><blockquote><p>一句话先记住:<strong>Minecraft 的世界是&quot;同一格上叠着多层数据 + 一根注册表主轴穿透所有层&quot;;理解它的关键不是数清有多少种东西,而是看清每种东西活在哪一层、以及一格数据怎么在这些层之间流动。</strong></p></blockquote><hr><h2 id="一、先立一条正交轴-类型-vs-实例" tabindex="-1">一、先立一条正交轴:类型 vs 实例 <a class="header-anchor" href="#一、先立一条正交轴-类型-vs-实例" aria-label="Permalink to &quot;一、先立一条正交轴:类型 vs 实例&quot;">​</a></h2><p>在画总图之前,必须先讲清一条<strong>横切所有层</strong>的轴,否则总图会看不懂。</p><p>前面我们反复遇到一个现象:几乎每种&quot;东西&quot;都分成<strong>两层</strong>。</p><table tabindex="0"><thead><tr><th>类型层(单例,定义行为,在注册表里)</th><th>实例层(逐个存在,带数据,要存盘)</th></tr></thead><tbody><tr><td><code>Block</code>(石头这&quot;类&quot;)</td><td>BlockState 下标(世界里那一格)</td></tr><tr><td><code>Item</code>(钻石剑这&quot;类&quot;)</td><td><code>ItemStack</code>(你背包里这一把)</td></tr><tr><td><code>EntityType</code>(僵尸这&quot;类&quot;)</td><td><code>Entity</code>(刷出来的那只僵尸)</td></tr><tr><td><code>BlockEntityType</code>(箱子这&quot;类&quot;)</td><td><code>BlockEntity</code>(这个坐标的箱子)</td></tr><tr><td><code>Fluid</code>(水这&quot;类&quot;)</td><td><code>FluidState</code>(这格的水)</td></tr></tbody></table><p>左列是游戏启动时就固定下来的&quot;模板&quot;,像面向对象里的&quot;类&quot;,全游戏每种只有一个实例,登记在注册表里。右列才是世界里逐个存在、要进 chunk、要序列化的&quot;对象&quot;。</p><p><strong>为什么这条轴重要?</strong> 因为它解释了 Minecraft 最核心的省法:</p><ul><li>千万个石头方块,共享<strong>同一个</strong> <code>Block</code> 单例和同一个 BlockState 引用,世界里每格只存一个&quot;调色板下标&quot;。</li><li>一种方块的所有行为(硬度、碰撞、掉落、tick 逻辑)只写一份,挂在类型层。</li></ul><p>这条轴是<strong>正交的</strong>——它不是&quot;另一类东西&quot;,而是看待每一类东西的两个视角。后面总图里几乎每个名词,你都要意识到它同时活在这两层上。</p><hr><h2 id="二、一个反直觉的事实-一格上叠着好几层" tabindex="-1">二、一个反直觉的事实:一格上叠着好几层 <a class="header-anchor" href="#二、一个反直觉的事实-一格上叠着好几层" aria-label="Permalink to &quot;二、一个反直觉的事实:一格上叠着好几层&quot;">​</a></h2><p>新手脑子里的世界是&quot;每个格子里放一个方块&quot;,一格 = 一个东西。<strong>这是错的。</strong> 同一个坐标上,实际叠着好几层彼此半独立的数据:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>坐标 (x, y, z) 上同时存在:</span></span>
<span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  BlockState   ← 方块状态(楼梯、朝向、含水标记) │</span></span>
<span class="line"><span>│  FluidState   ← 流体状态(这格有没有水、level)  │  ← 与方块半独立</span></span>
<span class="line"><span>│  Light        ← 光照(BlockLight + SkyLight)    │  ← 两个通道各 0-15</span></span>
<span class="line"><span>│  (BlockEntity) ← 少数方块才有的 NBT 附加/渲染锚 │  ← 可选</span></span>
<span class="line"><span>│  Biome        ← 4×4×4 粒度的气候标签(共享)     │  ← 粗粒度</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><p>这正是<strong>含水机制(waterlogging)</strong> 能存在的原因:一个被水淹的楼梯,它的 BlockState 仍然是楼梯,FluidState 才是水——两层叠在一格上,各存各的,各自 tick。</p><p>记住这一点,你才不会问出&quot;水到底算不算方块&quot;这种问题:水既有自己的 FluidState 层,在源方块处又对应一个 BlockState,它跨了两层。</p><hr><h2 id="三、两个不同的问题-别把它们混成一个" tabindex="-1">三、两个不同的问题:别把它们混成一个 <a class="header-anchor" href="#三、两个不同的问题-别把它们混成一个" aria-label="Permalink to &quot;三、两个不同的问题:别把它们混成一个&quot;">​</a></h2><p>学到这里很多人会不停追问&quot;还有没有别的类别&quot;,问到停不下来。根本原因是**&quot;类别&quot;这个词跨了两个性质完全不同的问题**,一个有限、一个无限,必须分开。</p><p><strong>问题 A:世界里有哪些&quot;逐实例对象 / 数据层&quot;?</strong> —— 这是<strong>有限集</strong>,基本可以穷举:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>方块 BlockState · 流体 FluidState · 方块实体 BlockEntity</span></span>
<span class="line"><span>· 实体 Entity · 物品 ItemStack · 生物群系 Biome · 光照 Light</span></span>
<span class="line"><span>(· 粒子 Particle:纯客户端视觉,算半个)</span></span></code></pre></div><p>这张表问到这里就基本到头了，再问&quot;还有没有&quot;，答案趋近于&quot;没有了&quot;。</p><p><strong>问题 B:引擎里有哪些&quot;系统 / 层&quot;?</strong> —— 这是<strong>开放集</strong>,可以一直往下拆:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>修饰层(属性/状态效果/附魔/数据组件) · 运行时信号(红石/游戏事件/声音/调度)</span></span>
<span class="line"><span>· 交互会话(菜单/网络) · 元系统(注册表/标签) · 容器(维度/存档/数据包)</span></span>
<span class="line"><span>· 还能继续:碰撞形状 VoxelShape、AI 的 Brain/记忆、结构生成、世界生成噪声路由…</span></span></code></pre></div><p>因为这问的不再是&quot;世界里有什么&quot;,而是&quot;游戏怎么运转&quot;——而运转的系统永远能再细分。</p><p><strong>所以:</strong> 如果你问的是&quot;平行于方块的对象类别&quot;(A),那张七项表已经到头;如果你问的是&quot;引擎还有多少系统&quot;(B),那它本来就没有尽头。把这条线画清楚,你就不会再有&quot;是不是漏了什么&quot;的焦虑。</p><hr><h2 id="四、分层架构总图" tabindex="-1">四、分层架构总图 <a class="header-anchor" href="#四、分层架构总图" aria-label="Permalink to &quot;四、分层架构总图&quot;">​</a></h2><p>现在可以上总图了。从下往上 = 从&quot;静态怎么存&quot;到&quot;动起来怎么交互&quot;;最左边的注册表是穿透所有层的主轴。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╔══════════════════════════════════════════════════════════════════╗</span></span>
<span class="line"><span>║  Minecraft 数据与运行架构总图(Java 版 1.18+)                     ║</span></span>
<span class="line"><span>╚══════════════════════════════════════════════════════════════════╝</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 0. 元层:注册表 Registry —— 一切&quot;类型&quot;的总账                     │</span></span>
<span class="line"><span>│    · 命名空间ID(minecraft:stone)+ 数字ID                       │</span></span>
<span class="line"><span>│    · 启动冻结 → 进服同步 → palette/网络/存盘都用数字ID            │</span></span>
<span class="line"><span>│    · 静态(方块/物品/实体类型) + 动态(生物群系/维度,数据驱动)│</span></span>
<span class="line"><span>│    · 标签 Tag:给注册项分组(#minecraft:logs)                   │</span></span>
<span class="line"><span>│    ▲ 下面每一层的&quot;类型&quot;,都是这里的条目                          │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────── 正交轴:类型 vs 实例(横切所有层)──────────────┐</span></span>
<span class="line"><span>│  类型层(单例,在注册表里)      │  实例层(逐个,带数据,要存盘)│</span></span>
<span class="line"><span>│  Block / Item / EntityType /    │  BlockState下标 / ItemStack /  │</span></span>
<span class="line"><span>│  Fluid / BlockEntityType …      │  Entity / FluidState …         │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 1. 世界里的逐实例对象 / 数据层(占坐标、进 chunk、要存盘)        │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│   同一格叠多层 ──►  ┌── 方块 BlockState (网格,可共享,palette)  │</span></span>
<span class="line"><span>│                     ├── 流体 FluidState (与方块叠加,独立tick)   │</span></span>
<span class="line"><span>│                     └── 光照 Light      (BlockLight+SkyLight)    │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│   方块的附加 ─────►   方块实体 BlockEntity                       │</span></span>
<span class="line"><span>│                       · 存逐实例数据(箱子物品/告示牌文字)       │</span></span>
<span class="line"><span>│                       · 或特殊渲染(床/箱子开盖动画)            │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│   脱离网格 ───────►   实体 Entity(浮点坐标,每个都 tick)        │</span></span>
<span class="line"><span>│                       · LivingEntity→Mob/Player,投射物,掉落物  │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│   寄生在容器里 ───►   物品 ItemStack(背包/箱子/手上;掉地→实体) │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│   粗粒度坐标标签 ─►   生物群系 Biome(4×4×4,palette,定气候/染色)│</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│   (纯客户端视觉)─►   粒子 Particle(不存盘、不tick、不交互)     │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 2. 修饰层(贴在 实体/物品 上,改行为,不是独立对象)              │</span></span>
<span class="line"><span>│   属性 Attribute(生命/移速/攻击)· 状态效果 MobEffect(每tick结算)│</span></span>
<span class="line"><span>│   附魔 Enchantment · 数据组件 Data Component(1.20.5+ 物品新模型) │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 3. 运行时信号(不存盘,只在 tick 间流动)                         │</span></span>
<span class="line"><span>│   红石(邻居更新级联)· 游戏事件/振动 GameEvent(幽匿)            │</span></span>
<span class="line"><span>│   scheduled tick / random tick · 声音 SoundEvent                 │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 4. 交互 / 会话(玩家与世界之间,临时)                            │</span></span>
<span class="line"><span>│   菜单 Menu/容器(开箱子时同步槽位)· 网络连接 / 玩家会话         │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 5. 运行驱动:Tick 系统                                           │</span></span>
<span class="line"><span>│   20 TPS 主循环(时间累加器,追不上→掉TPS)                       │</span></span>
<span class="line"><span>│   scheduled tick 队列(水流/红石延迟)· random tick 抽样(生长)  │</span></span>
<span class="line"><span>│   邻居通知级联 · 实体 tick(AI/A*/AABB)· tickBlockEntities       │</span></span>
<span class="line"><span>│   chunk ticket 等级(&lt;32 实体tick / 32-33 方块tick / 外圈仅加载)│</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 6. 持久化:存储                                                  │</span></span>
<span class="line"><span>│   Chunk(16×16×384,分 16³ section)                              │</span></span>
<span class="line"><span>│   section: PalettedContainer(palette + bit-packed Long_Array)   │</span></span>
<span class="line"><span>│   NBT(带类型的二进制树,序列化一切逐实例数据)                   │</span></span>
<span class="line"><span>│   Region 文件 .mca(1024 chunk;8KB头:位置表+时间戳表;4KB扇区) │</span></span>
<span class="line"><span>│   超大chunk→.mcc · 实体→entities/ · 兴趣点→poi/ · level.dat      │</span></span>
<span class="line"><span>│   地形不存,靠 种子+噪声 确定性生成,只存改过的 chunk             │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 7. 最外层容器                                                    │</span></span>
<span class="line"><span>│   维度 Level/Dimension(主世界/下界/末地/自定义,各自独立chunk)  │</span></span>
<span class="line"><span>│   存档 World(level.dat:种子/出生点/游戏规则/DataVersion)       │</span></span>
<span class="line"><span>│   数据包 Datapack:配方/战利品表/进度/标签/动态注册表(JSON定义)│</span></span>
<span class="line"><span>│   DataFixerUpper:按 DataVersion 跨版本迁移旧存档                 │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="五、如何读这张图" tabindex="-1">五、如何读这张图 <a class="header-anchor" href="#五、如何读这张图" aria-label="Permalink to &quot;五、如何读这张图&quot;">​</a></h2><p>这张图不是用来背的,是用来&quot;定位&quot;的。三条读法:</p><p><strong>纵向:从&quot;存&quot;到&quot;动&quot;再到&quot;交互&quot;。</strong> 下层(6/7)回答&quot;静态的数据怎么躺在硬盘上&quot;,中层(5)回答&quot;它怎么被驱动起来&quot;,上层(1-4)回答&quot;动起来之后世界里有哪些东西、哪些状态、哪些交互&quot;。任何一个游戏现象,你都能在某一层找到它的落点。</p><p><strong>横向:注册表是穿透所有层的主轴。</strong> 每一层的&quot;类型&quot;都来自第 0 层;存盘 palette 里的数字 ID、进服时的注册表同步、跨版本的 DataFixerUpper 迁移,全都绕着注册表转。理解了它,前面零散的点就被一根线串起来了。</p><p><strong>一格 = 多层叠加。</strong> 这是最反直觉、也最关键的一点(第二节讲过):同一坐标上叠着 BlockState + FluidState + Light,可能还挂一个 BlockEntity。别再把世界想成&quot;每格一个东西&quot;。</p><p>还有那条<strong>正交轴</strong>别忘了:图里几乎每个名词,都同时活在&quot;注册表里的单例模板&quot;和&quot;世界里的逐实例对象&quot;两层上。</p><hr><h2 id="六、一个-163-section-的生命周期" tabindex="-1">六、一个 16³ Section 的生命周期 <a class="header-anchor" href="#六、一个-163-section-的生命周期" aria-label="Permalink to &quot;六、一个 16³ Section 的生命周期&quot;">​</a></h2><p>光有静态分层还不够。真正把所有层缝起来的,是数据<strong>流动</strong>的过程。下面让一个 16×16×16 的 section(以及里面的一格方块)从出生到重新加载,在这张图上走一遍。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  一个 16³ Section 的一生</span></span>
<span class="line"><span>═══════════════════════════════════════════════════════════════</span></span>
<span class="line"><span></span></span>
<span class="line"><span>① 生成(第 0/1/6 层:噪声 → PalettedContainer)</span></span>
<span class="line"><span>   世界生成器对每个坐标问噪声函数(种子+坐标→确定值)</span></span>
<span class="line"><span>   → 决定每格是空气/石头/矿石…</span></span>
<span class="line"><span>   → 写入内存中的 PalettedContainer:</span></span>
<span class="line"><span>        palette = [air, stone]          ← 局部调色板</span></span>
<span class="line"><span>        data    = bit-packed Long_Array ← 每格只存调色板下标</span></span>
<span class="line"><span>   注:此刻硬盘上什么都没有,地形是&quot;算出来&quot;的,不是&quot;存出来&quot;的</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>② 运行(第 5 层 Tick 系统 驱动 第 1 层 数据)</span></span>
<span class="line"><span>   只要该 chunk 进入 ticking 等级(ticket level &lt; 32):</span></span>
<span class="line"><span>     · random tick 抽样   → 抽到作物/草 → 生长,改写 PalettedContainer</span></span>
<span class="line"><span>     · scheduled tick 队列 → 水流逐圈扩散、红石中继延迟</span></span>
<span class="line"><span>     · setBlock + 邻居通知 → 红石级联、沙子下落、活塞响应</span></span>
<span class="line"><span>   每次方块变化:</span></span>
<span class="line"><span>     · 调色板可能新增种类(放下一块从未出现的方块)</span></span>
<span class="line"><span>     · 种类变多 → bitsPerEntry 自动增大,Long_Array 重新打包</span></span>
<span class="line"><span>     · 种类变少/归一 → 位宽收缩,甚至退化成单值省掉数组</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>③ 卸载 或 自动保存(第 1 层 → 第 6 层:序列化下盘)</span></span>
<span class="line"><span>   触发:周期性自动保存 / 玩家离开 chunk / 关服</span></span>
<span class="line"><span>     · PalettedContainer 几乎原样序列化成 block_states:</span></span>
<span class="line"><span>          { palette: [...], data: Long_Array }   ← 内存与磁盘同构!</span></span>
<span class="line"><span>     · 连同 block_entities、未结算的 block_ticks/fluid_ticks、</span></span>
<span class="line"><span>       Heightmaps、biomes、光照 → 打包成该 chunk 的 NBT 树</span></span>
<span class="line"><span>     · NBT 树 → zlib 压缩</span></span>
<span class="line"><span>     · 在 .mca 里找一段连续空闲扇区写入(按 4KB 对齐)</span></span>
<span class="line"><span>     · 更新文件头的 location table(偏移+扇区数)与 timestamp table</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>④ 再加载(第 6 层 → 第 1 层:反向走一遍)</span></span>
<span class="line"><span>   玩家走回来:</span></span>
<span class="line"><span>     · 查 location table → 得到扇区偏移与长度</span></span>
<span class="line"><span>     · seek 到扇区 → 读出 → 看压缩类型字节 → 解压</span></span>
<span class="line"><span>     · 解析 NBT 树</span></span>
<span class="line"><span>     · 用 block_states 的 palette + Long_Array 重建 PalettedContainer</span></span>
<span class="line"><span>   回到 ②,继续被 tick 驱动</span></span></code></pre></div><p>注意第 ③ 步那行注释:<strong>内存里的 PalettedContainer 和磁盘上的 <code>block_states</code> 结构同构</strong>——都是&quot;局部调色板 + 紧凑位数组&quot;。所以保存几乎是&quot;原样倒出去&quot;,加载几乎是&quot;原样读回来&quot;,中间没有昂贵的格式转换。这不是巧合,是刻意的设计。</p><hr><h2 id="七、收尾-一条主线贯穿始终" tabindex="-1">七、收尾:一条主线贯穿始终 <a class="header-anchor" href="#七、收尾-一条主线贯穿始终" aria-label="Permalink to &quot;七、收尾:一条主线贯穿始终&quot;">​</a></h2><p>如果这整个系列只让你记住一句话,那就是这条贯穿十二篇的主线:</p><blockquote><p><strong>能算出来的就不存,能共享的就不复制,内存与磁盘尽量同构。</strong></p></blockquote><p>回头看,Minecraft 几乎所有的&quot;省&quot;和&quot;快&quot;,都是这一招的不同变体:</p><ul><li><strong>能算不存</strong>:无限地形不进硬盘,靠种子+噪声确定性现算(第 01/02 篇);只有玩家改过的 chunk 才落盘(第 07 篇);战利品箱打开前只存&quot;配方+种子&quot;,物品现场生成(第 09 篇)。</li><li><strong>能享不复制</strong>:千万个石头共享一个 BlockState 引用,世界里每格只存调色板下标(第 09 篇);BlockState 全局调色板让方块没有逐实例数据。</li><li><strong>内存与磁盘同构</strong>:PalettedContainer 与 <code>block_states</code> 结构一致,加载零转换(第 03/08 篇与本篇)。</li></ul><p>把这条主线和这张分层总图一起记住,你看 Minecraft 就不再是&quot;一堆方块的游戏&quot;,而是一个<strong>把确定性生成、数据共享和结构同构做到极致的体素引擎</strong>。每一个你在游戏里观察到的现象——麦子参差成熟、远处机器停摆、含水的楼梯、打不开的箱子——都能在这张图上找到它的层、找到它的因。</p><p>这就是这个系列想留给你的东西:不是答案的清单,而是一张能自己推出答案的地图。</p>`,53)])])}const h=s(e,[["render",l]]);export{q as __pageData,h as default};
